-- 1. Extend service_coverage_areas
ALTER TABLE public.service_coverage_areas
  ADD COLUMN IF NOT EXISTS city TEXT,
  ADD COLUMN IF NOT EXISTS province TEXT NOT NULL DEFAULT 'QC',
  ADD COLUMN IF NOT EXISTS internet_available BOOLEAN NOT NULL DEFAULT true,
  ADD COLUMN IF NOT EXISTS internet_max_speed TEXT NOT NULL DEFAULT '1 Gbps',
  ADD COLUMN IF NOT EXISTS tv_available BOOLEAN NOT NULL DEFAULT true,
  ADD COLUMN IF NOT EXISTS mobile_available BOOLEAN NOT NULL DEFAULT true,
  ADD COLUMN IF NOT EXISTS network_provider TEXT NOT NULL DEFAULT 'Bell';

CREATE INDEX IF NOT EXISTS idx_coverage_postal_prefix ON public.service_coverage_areas(postal_prefix);
CREATE INDEX IF NOT EXISTS idx_coverage_province ON public.service_coverage_areas(province);

-- Backfill booleans from existing available_services JSONB (best-effort)
UPDATE public.service_coverage_areas
SET
  internet_available = COALESCE((available_services::jsonb ? 'internet') OR (available_services::jsonb ? 'Internet'), internet_available),
  tv_available       = COALESCE((available_services::jsonb ? 'tv')       OR (available_services::jsonb ? 'TV'),       tv_available),
  mobile_available   = COALESCE((available_services::jsonb ? 'mobile')   OR (available_services::jsonb ? 'Mobile'),   mobile_available)
WHERE available_services IS NOT NULL;

