ON CONFLICT (postal_prefix) DO UPDATE
SET city = EXCLUDED.city,
    province = EXCLUDED.province,
    coverage_type = EXCLUDED.coverage_type,
    internet_available = EXCLUDED.internet_available,
    tv_available = EXCLUDED.tv_available,
    mobile_available = EXCLUDED.mobile_available,
    network_provider = EXCLUDED.network_provider,
    is_active = true,
    updated_at = now();

-- 3. coverage_waitlist table
CREATE TABLE IF NOT EXISTS public.coverage_waitlist (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  email TEXT NOT NULL,
  postal_code TEXT,
  city TEXT,
  notes TEXT,
  notified_at TIMESTAMPTZ,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_coverage_waitlist_email ON public.coverage_waitlist(email);
CREATE INDEX IF NOT EXISTS idx_coverage_waitlist_postal ON public.coverage_waitlist(postal_code);

ALTER TABLE public.coverage_waitlist ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "Anyone can join coverage waitlist" ON public.coverage_waitlist;
CREATE POLICY "Anyone can join coverage waitlist"
  ON public.coverage_waitlist
  FOR INSERT
  TO public
  WITH CHECK (true);

DROP POLICY IF EXISTS "Admins manage coverage waitlist" ON public.coverage_waitlist;
CREATE POLICY "Admins manage coverage waitlist"
  ON public.coverage_waitlist
  FOR ALL
  TO authenticated
  USING (public.has_role(auth.uid(), 'admin'))
  WITH CHECK (public.has_role(auth.uid(), 'admin'));

-- 4. Public read + admin write on service_coverage_areas
ALTER TABLE public.service_coverage_areas ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "Public can read coverage zones" ON public.service_coverage_areas;
CREATE POLICY "Public can read coverage zones"
  ON public.service_coverage_areas
  FOR SELECT
  TO public
  USING (true);

DROP POLICY IF EXISTS "Admins manage coverage zones" ON public.service_coverage_areas;
CREATE POLICY "Admins manage coverage zones"
  ON public.service_coverage_areas
  FOR ALL
  TO authenticated
  USING (public.has_role(auth.uid(), 'admin'))
  WITH CHECK (public.has_role(auth.uid(), 'admin'));